 1	import React, { FC, useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { modelToGroupVersionKind, PodModel } from '@kubevirt-ui/kubevirt-api/console';
 5	import { killUploadPVC } from '@kubevirt-utils/hooks/useCDIUpload/utils';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { K8sResourceCommon, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 8	import {
 9	  Button,
10	  ButtonVariant,
11	  Checkbox,
12	  EmptyStateActions,
13	  EmptyStateBody,
14	  EmptyStateIcon,
15	  Split,
16	  SplitItem,
17	  Stack,
18	  StackItem,
19	  Title,
20	} from '@patternfly/react-core';
21	import { ErrorCircleOIcon } from '@patternfly/react-icons';
22	
23	import { resourcePath } from '../../utils/utils';
24	
25	type CDIInitErrorStatus = {
26	  namespace: string;
27	  onErrorClick: () => void;
28	  pvcName: string;
29	};
30	
31	const CDIInitErrorStatus: FC<CDIInitErrorStatus> = ({ namespace, onErrorClick, pvcName }) => {
32	  const { t } = useKubevirtTranslation();
33	  const [shouldKillDv, setShouldKillDv] = useState<boolean>(true);
34	  const [pod, podLoaded, podError] = useK8sWatchResource<K8sResourceCommon>({
35	    groupVersionKind: modelToGroupVersionKind(PodModel),
36	    name: `cdi-upload-${pvcName}`,
37	    namespace,
38	  });
39	
40	  const navigate = useNavigate();
41	
42	  const onClick = async () => {
43	    shouldKillDv && (await killUploadPVC(pvcName, namespace));
44	    onErrorClick();
45	  };
46	
47	  return (
48	    <>
49	      <EmptyStateIcon color="#cf1010" icon={ErrorCircleOIcon} />
50	      <Title headingLevel="h4" size="lg">
51	        {t('CDI Error: Could not initiate Data Volume')}
52	      </Title>
53	      <EmptyStateBody>
54	        <Stack hasGutter>
55	          <StackItem>
56	            {t(
57	              'Data Volume failed to initiate upload, you can either delete the Data Volume and try again, or check logs',
58	            )}
59	          </StackItem>
60	          <StackItem>
61	            <Split>
62	              <SplitItem isFilled />
63	              <Checkbox
64	                aria-label="kill datavolume checkbox"
65	                data-checked-state={shouldKillDv}
66	                id="approve-checkbox"
67	                isChecked={shouldKillDv}
68	                label={t('Delete Data Volume: {{pvcName}}', { pvcName })}
69	                onChange={(_event, checked) => setShouldKillDv(checked)}
70	              />
71	              <SplitItem isFilled />
72	            </Split>
73	          </StackItem>
74	        </Stack>
75	      </EmptyStateBody>
76	      <Button id="cdi-upload-error-btn" onClick={onClick} variant="primary">
77	        {shouldKillDv ? t('Back to form (Deletes DataVolume)') : t('Back to form')}
78	      </Button>
79	      {podLoaded && !podError && pod && (
80	        <EmptyStateActions>
81	          <Button
82	            onClick={() =>
83	              navigate(`${resourcePath(PodModel, pod?.metadata?.name, namespace)}/logs`)
84	            }
85	            id="cdi-upload-check-logs"
86	            variant={ButtonVariant.link}
87	          >
88	            {t('Check logs')}
89	          </Button>
90	        </EmptyStateActions>
91	      )}
92	    </>
93	  );
94	};
95	
96	export default CDIInitErrorStatus;

